-- 開発用シード（固定 UUID）。新スキーマ構成（hr/project/staffing_request/work_assignment）向け。












SELECT e.id, e.name, e.updated_at
FROM hr.employee e
WHERE e.id IN (
  '11111111-1111-4111-8111-111111110301',
  '11111111-1111-4111-8111-111111110302'
);

SELECT c.id, c.name, c.updated_at
FROM project.customer c
WHERE c.id = '77777777-7777-4777-8777-777777770101';
